1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = {
9	  op: "quote";
10	  items: Item[];
11	};
12	
13	export type Step = QuoteStep;
14	
15	export type Scenario = {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	};
19	
20	export type QuoteResult = { premium: number };
21	export type StepResult = QuoteResult;
22	
23	export type ScenarioResult = {
24	  results: StepResult[];
25	};
26	
27	const PROCESSING_FEE = 5;
28	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
29	const BLOCK_OF_THREE_DISCOUNT = 15;
30	
31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const blockOfThreeDiscount = (alikeComponentCount: number): number =>
41	  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
42	
43	const COMPONENT_TYPES = ["rune", "moonstone"];
44	
45	const countItemsOfType = (items: Item[], type: string): number =>
46	  items.filter((item) => item.type === type).length;
47	
48	const CURSE_SURCHARGE_RATE = 0.5;
49	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
50	const HIGH_ENCHANTMENT_THRESHOLD = 5;
51	const LOYALTY_DISCOUNT_RATE = 0.2;
52	const LOYALTY_YEARS_THRESHOLD = 2;
53	
54	const isCursed = (item: Item): boolean => item.cursed === true;
55	const isHighlyEnchanted = (item: Item): boolean =>
56	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
57	
58	const ITEM_SURCHARGE_RATES: ReadonlyArray<{
59	  applies: (item: Item) => boolean;
60	  rate: number;
61	}> = [
62	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
63	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
64	];
65	
66	const surchargesForItem = (item: Item): number => {
67	  const base = BASE_PREMIUM[item.type];
68	  return ITEM_SURCHARGE_RATES.reduce(
69	    (sum, { applies, rate }) => sum + (applies(item) ? base * rate : 0),
70	    0,
71	  );
72	};
73	
74	const sumItemSpecificSurcharges = (items: Item[]): number =>
75	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
76	
77	const calculateBasePremium = (items: Item[]): number => {
78	  const subtotal = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
79	  const totalDiscount = COMPONENT_TYPES.reduce(
80	    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
81	    0,
82	  );
83	  return subtotal - totalDiscount;
84	};
85	
86	const loyaltyDiscount = (basePremium: number, customer: Scenario["customer"]): number =>
87	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
88	
89	const quote = (step: QuoteStep, customer: Scenario["customer"]): QuoteResult => {
90	  const basePremium = calculateBasePremium(step.items);
91	  const itemSurcharges = sumItemSpecificSurcharges(step.items);
92	  const firstContractSurcharge = basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
93	  const premium = Math.ceil(
94	    basePremium +
95	      itemSurcharges +
96	      firstContractSurcharge -
97	      loyaltyDiscount(basePremium, customer) +
98	      PROCESSING_FEE,
99	  );
100	  return { premium };
101	};
102	
103	export const runScenario = (scenario: Scenario): ScenarioResult => {
104	  const results = scenario.steps.map((step) => quote(step, scenario.customer));
105	  return { results };
106	};
